class Solution {
public:
    int maxVowels(string s, int k) {
        int count = 0, maxCount = 0;
        unordered_set<char> vowels = {'a', 'e', 'i', 'o', 'u'};
        for (int i = 0; i < s.size(); ++i) {
            if (vowels.count(s[i])) count++;
            if (i >= k && vowels.count(s[i - k])) count--;
            maxCount = max(maxCount, count);
        }
        return maxCount;
    }
};
